4	 * Warning from the model provider for this call. The call will proceed, but e.g.
5	 * some settings might not be supported, which can lead to suboptimal results.
6	 */
7	export type ImageModelV2CallWarning =
8	  | {
9	      type: 'unsupported-setting';
10	      setting: keyof ImageModelV2CallOptions;
11	      details?: string;
12	    }
13	  | {
14	      type: 'other';
15	      message: string;
