124	  async doGenerate({
125	    prompt,
126	    n,
127	    size,
128	    aspectRatio,
129	    seed,
130	    providerOptions,
131	    headers,
132	    abortSignal,
133	    files,
134	    mask,
135	  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
