172	        });
173	      }
174	    }
175	
176	    // Warn about mask - Fireworks Kontext models don't support explicit masks
177	    if (mask != null) {
178	      warnings.push({
179	        type: 'unsupported',
180	        feature: 'mask',
181	        details:
182	          'Fireworks Kontext models do not support explicit masks. Use the prompt to describe the areas to edit.',
183	      });
184	    }
185	
186	    const splitSize = size?.split('x');
187	    const currentDate = this.config._internal?.currentDate?.() ?? new Date();
188	    const combinedHeaders = combineHeaders(this.config.headers(), headers);
189	
190	    const body = {
191	      prompt,
192	      aspect_ratio: aspectRatio,
193	      seed,
194	      samples: n,
195	      ...(inputImage && { input_image: inputImage }),
196	      ...(splitSize && { width: splitSize[0], height: splitSize[1] }),
197	      ...(providerOptions.fireworks ?? {}),
