200	    // Handle async models that require polling (e.g., flux-kontext-*)
201	    if (backendConfig?.urlFormat === 'workflows_async') {
202	      return this.doGenerateAsync({
203	        body,
204	        headers: combinedHeaders,
205	        abortSignal,
206	        warnings,
207	        currentDate,
208	      });
209	    }
210	
211	    // Handle sync models that return binary directly
212	    const { value: response, responseHeaders } = await postJsonToApi({
213	      url: getUrlForModel(this.config.baseURL, this.modelId),
214	      headers: combinedHeaders,
215	      body,
216	      failedResponseHandler: createStatusCodeErrorResponseHandler(),
217	      successfulResponseHandler: createBinaryResponseHandler(),
218	      abortSignal,
219	      fetch: this.config.fetch,
220	    });
221	
222	    return {
223	      images: [response],
224	      warnings,
225	      response: {
226	        timestamp: currentDate,
227	        modelId: this.modelId,
228	        headers: responseHeaders,
229	      },
