233	  /**
234	   * Handles async image generation for models like flux-kontext-* that return
235	   * a request_id and require polling for results.
236	   */
237	  private async doGenerateAsync({
238	    body,
239	    headers,
240	    abortSignal,
241	    warnings,
242	    currentDate,
243	  }: {
244	    body: Record<string, unknown>;
245	    headers: Record<string, string | undefined>;
246	    abortSignal: AbortSignal | undefined;
247	    warnings: Array<SharedV3Warning>;
248	    currentDate: Date;
249	  }): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
250	    // Submit the generation request
251	    const { value: submitResponse } = await postJsonToApi({
252	      url: getUrlForModel(this.config.baseURL, this.modelId),
253	      headers,
254	      body,
255	      failedResponseHandler: createStatusCodeErrorResponseHandler(),
256	      successfulResponseHandler: createJsonResponseHandler(
257	        asyncSubmitResponseSchema,
258	      ),
259	      abortSignal,
260	      fetch: this.config.fetch,
261	    });
262	
263	    const requestId = submitResponse.request_id;
264	
265	    // Poll for the result
266	    const imageUrl = await this.pollForImageUrl({
267	      requestId,
268	      headers,
269	      abortSignal,
270	    });
271	
272	    // Download the image from the URL
273	    const { value: imageBytes, responseHeaders } = await getFromApi({
274	      url: imageUrl,
275	      headers,
276	      abortSignal,
277	      failedResponseHandler: createStatusCodeErrorResponseHandler(),
278	      successfulResponseHandler: createBinaryResponseHandler(),
279	      fetch: this.config.fetch,
280	    });
281	
282	    return {
283	      images: [imageBytes],
284	      warnings,
285	      response: {
286	        timestamp: currentDate,
287	        modelId: this.modelId,
288	        headers: responseHeaders,
289	      },
290	    };
291	  }
292	
293	  /**
294	   * Polls the get_result endpoint until the image is ready.
295	   */
296	  private async pollForImageUrl({
297	    requestId,
298	    headers,
299	    abortSignal,
300	  }: {
301	    requestId: string;
302	    headers: Record<string, string | undefined>;
303	    abortSignal: AbortSignal | undefined;
304	  }): Promise<string> {
305	    const pollIntervalMillis =
306	      this.config.pollIntervalMillis ?? DEFAULT_POLL_INTERVAL_MILLIS;
307	    const pollTimeoutMillis =
308	      this.config.pollTimeoutMillis ?? DEFAULT_POLL_TIMEOUT_MILLIS;
309	    const maxPollAttempts = Math.ceil(
310	      pollTimeoutMillis / Math.max(1, pollIntervalMillis),
311	    );
312	
313	    const pollUrl = getPollUrlForModel(this.config.baseURL, this.modelId);
314	
315	    for (let i = 0; i < maxPollAttempts; i++) {
316	      const { value: pollResponse } = await postJsonToApi({
317	        url: pollUrl,
318	        headers,
319	        body: { id: requestId },
320	        failedResponseHandler: createStatusCodeErrorResponseHandler(),
321	        successfulResponseHandler: createJsonResponseHandler(
322	          asyncPollResponseSchema,
323	        ),
324	        abortSignal,
325	        fetch: this.config.fetch,
326	      });
327	
328	      const status = pollResponse.status;
329	
330	      if (status === 'Ready') {
331	        const imageUrl = pollResponse.result?.sample;
332	        if (typeof imageUrl === 'string') {
333	          return imageUrl;
334	        }
335	        throw new Error(
336	          'Fireworks poll response is Ready but missing result.sample',
337	        );
338	      }
339	
340	      if (status === 'Error' || status === 'Failed') {
341	        throw new Error(
342	          `Fireworks image generation failed with status: ${status}`,
343	        );
344	      }
345	
346	      // Wait before next poll attempt
347	      await delay(pollIntervalMillis);
348	    }
349	
350	    throw new Error(
351	      `Fireworks image generation timed out after ${pollTimeoutMillis}ms`,
352	    );
353	  }
354	}
