1	/**
2	 * Converts an input object to FormData for multipart/form-data requests.
3	 *
4	 * Handles the following cases:
5	 * - `null` or `undefined` values are skipped
6	 * - Arrays with a single element are appended as a single value
7	 * - Arrays with multiple elements are appended with `[]` suffix (e.g., `image[]`)
8	 *   unless `useArrayBrackets` is set to `false`
9	 * - All other values are appended directly
10	 *
11	 * @param input - The input object to convert. Use a generic type for type validation.
12	 * @param options - Optional configuration object.
13	 * @param options.useArrayBrackets - Whether to add `[]` suffix for multi-element arrays.
14	 *   Defaults to `true`. Set to `false` for APIs that expect repeated keys without brackets.
15	 * @returns A FormData object containing the input values.
16	 *
17	 * @example
18	 * ```ts
19	 * type MyInput = {
20	 *   model: string;
21	 *   prompt: string;
22	 *   images: Blob[];
23	 * };
24	 *
25	 * const formData = convertToFormData<MyInput>({
26	 *   model: 'gpt-image-1',
27	 *   prompt: 'A cat',
28	 *   images: [blob1, blob2],
29	 * });
30	 * ```
31	 */
32	export function convertToFormData<T extends Record<string, unknown>>(
33	  input: T,
34	  options: { useArrayBrackets?: boolean } = {},
35	): FormData {
36	  const { useArrayBrackets = true } = options;
37	  const formData = new FormData();
38	
39	  for (const [key, value] of Object.entries(input)) {
40	    if (value == null) {
41	      continue;
42	    }
43	
44	    if (Array.isArray(value)) {
45	      if (value.length === 1) {
46	        formData.append(key, value[0] as string | Blob);
47	        continue;
48	      }
49	
50	      const arrayKey = useArrayBrackets ? `${key}[]` : key;
51	      for (const item of value) {
52	        formData.append(arrayKey, item as string | Blob);
53	      }
54	      continue;
55	    }
56	
57	    formData.append(key, value as string | Blob);
58	  }
59	
60	  return formData;
61	}
