import { FetchFunction } from '@ai-sdk/provider-utils';
import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it } from 'vitest';
import { PixelArtImageModel } from './pixelart-image-model';

const prompt = 'A cute 8-bit dragon';

function createBasicModel({
  headers,
  fetch,
  currentDate,
}: {
  headers?: Record<string, string | undefined>;
  fetch?: FetchFunction;
  currentDate?: () => Date;
} = {}) {
  return new PixelArtImageModel('pixelart-standard', {
    provider: 'pixelart.image',
    baseURL: 'https://api.example.com',
    headers: headers ?? { 'api-key': 'test-key' },
    fetch,
    _internal: {
      currentDate,
    },
  });
}

const defaultResponse = {
  type: 'json-value' as const,
  body: {
    data: [
      {
        b64_json: 'dGVzdC1iYXNlNjQtaW1hZ2U=',
        style: 'pixel',
        pixel_density: 2,
      },
    ],
  },
};

describe('PixelArtImageModel', () => {
  const server = createTestServer({
    'https://api.example.com/images/generations': {
      response: defaultResponse,
    },
  });

  describe('constructor', () => {
    it('should expose correct provider and model information', () => {
      const model = createBasicModel();

      expect(model.provider).toBe('pixelart.image');
      expect(model.modelId).toBe('pixelart-standard');
      expect(model.specificationVersion).toBe('v3');
      expect(model.maxImagesPerCall).toBe(4);
    });
  });

  describe('doGenerate', () => {
    it('should pass the correct parameters', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: '256x256',
        aspectRatio: undefined,
        seed: 42,
        providerOptions: {},
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-standard',
        prompt,
        n: 1,
        size: '256x256',
        seed: 42,
      });
    });

    it('should pass aspect ratio when provided', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: '1:1',
        seed: undefined,
        providerOptions: {},
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-standard',
        prompt,
        n: 1,
        aspect_ratio: '1:1',
      });
    });

    it('should pass provider options (style and pixelDensity)', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: '128x128',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          pixelart: {
            style: 'retro',
            pixelDensity: 3,
          },
        },
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-standard',
        prompt,
        n: 1,
        size: '128x128',
        style: 'retro',
        pixel_density: 3,
      });
    });

    it('should pass through additional provider options', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          pixelart: {
            style: '8bit',
            custom_param: 'custom_value',
          },
        },
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-standard',
        prompt,
        n: 1,
        style: '8bit',
        custom_param: 'custom_value',
      });
    });

    it('should return base64 images from response', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(result.images).toHaveLength(1);
      expect(result.images[0]).toBe('dGVzdC1iYXNlNjQtaW1hZ2U=');
    });

    it('should return multiple images', async () => {
      server.urls[
        'https://api.example.com/images/generations'
      ].response = {
        type: 'json-value',
        body: {
          data: [
            { b64_json: 'image1base64', style: 'pixel', pixel_density: 1 },
            { b64_json: 'image2base64', style: 'pixel', pixel_density: 1 },
          ],
        },
      };

      const model = createBasicModel();
      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 2,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(result.images).toHaveLength(2);
      expect(result.images[0]).toBe('image1base64');
      expect(result.images[1]).toBe('image2base64');
    });

    it('should pass headers', async () => {
      const modelWithHeaders = createBasicModel({
        headers: {
          'Custom-Provider-Header': 'provider-header-value',
        },
      });

      await modelWithHeaders.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        providerOptions: {},
        headers: {
          'Custom-Request-Header': 'request-header-value',
        },
        size: undefined,
        seed: undefined,
        aspectRatio: undefined,
      });

      expect(server.calls[0].requestHeaders).toStrictEqual({
        'content-type': 'application/json',
        'custom-provider-header': 'provider-header-value',
        'custom-request-header': 'request-header-value',
      });
    });

    it('should warn when files are provided', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: [
          {
            type: 'file',
            data: new Uint8Array([137, 80, 78, 71]),
            mediaType: 'image/png',
          },
        ],
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(result.warnings).toContainEqual({
        type: 'unsupported-setting',
        setting: 'files',
        details: 'PixelArt does not support image editing with input files.',
      });
    });

    it('should warn when mask is provided', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: {
          type: 'file',
          data: new Uint8Array([255, 255, 255, 0]),
          mediaType: 'image/png',
        },
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(result.warnings).toContainEqual({
        type: 'unsupported-setting',
        setting: 'mask',
        details: 'PixelArt does not support inpainting with masks.',
      });
    });

    it('should handle API errors', async () => {
      server.urls[
        'https://api.example.com/images/generations'
      ].response = {
        type: 'error',
        status: 400,
        body: JSON.stringify({
          error: {
            message: 'Invalid style parameter',
            code: 'invalid_request',
          },
        }),
      };

      const model = createBasicModel();
      await expect(
        model.doGenerate({
          prompt,
          files: undefined,
          mask: undefined,
          n: 1,
          providerOptions: {},
          size: undefined,
          seed: undefined,
          aspectRatio: undefined,
        }),
      ).rejects.toMatchObject({
        message: 'Invalid style parameter',
        statusCode: 400,
        url: 'https://api.example.com/images/generations',
      });
    });

    describe('response metadata', () => {
      it('should include timestamp, headers and modelId in response', async () => {
        const testDate = new Date('2024-01-01T00:00:00Z');
        const model = createBasicModel({
          currentDate: () => testDate,
        });

        const result = await model.doGenerate({
          prompt,
          files: undefined,
          mask: undefined,
          n: 1,
          providerOptions: {},
          size: undefined,
          seed: undefined,
          aspectRatio: undefined,
        });

        expect(result.response).toStrictEqual({
          timestamp: testDate,
          modelId: 'pixelart-standard',
          headers: expect.any(Object),
        });
      });
    });

    describe('provider metadata', () => {
      it('should include style and pixel density in provider metadata', async () => {
        const model = createBasicModel();

        const result = await model.doGenerate({
          prompt,
          files: undefined,
          mask: undefined,
          n: 1,
          providerOptions: {},
          size: undefined,
          seed: undefined,
          aspectRatio: undefined,
        });

        expect(result.providerMetadata).toStrictEqual({
          pixelart: {
            images: [
              {
                style: 'pixel',
                pixelDensity: 2,
              },
            ],
          },
        });
      });

      it('should handle null metadata values', async () => {
        server.urls[
          'https://api.example.com/images/generations'
        ].response = {
          type: 'json-value',
          body: {
            data: [
              {
                b64_json: 'dGVzdA==',
                style: null,
                pixel_density: null,
              },
            ],
          },
        };

        const model = createBasicModel();
        const result = await model.doGenerate({
          prompt,
          files: undefined,
          mask: undefined,
          n: 1,
          providerOptions: {},
          size: undefined,
          seed: undefined,
          aspectRatio: undefined,
        });

        expect(result.providerMetadata).toStrictEqual({
          pixelart: {
            images: [
              {
                style: null,
                pixelDensity: null,
              },
            ],
          },
        });
      });
    });
  });
});

